args.sparql:
SELECT ?performerLabel WHERE {
  ?track rdfs:label "Asli Hip Hop"@en .
  ?track wdt:P2373 ?performer .
  ?performer rdfs:label ?performerLabel .
  FILTER (LANG(?performerLabel) = 'en')
}

SELECT ?performerLabel WHERE {
  ?track rdfs:label "Asli Hip Hop"@hi .
  ?track wdt:P175 ?performer .
  ?performer rdfs:label ?performerLabel .
  FILTER (LANG(?performerLabel) = 'en')
}
